const items = $input.all();

// Map para contar as ocorrências de cada valor no campo 'NOME'
const countMap = {};

// Contar ocorrências
items.forEach(item => {
    const key = item.json.NOME; // Campo NOME usado para checar duplicidade
    countMap[key] = (countMap[key] || 0) + 1;
});

// Filtrar apenas os itens duplicados
const duplicates = items.filter(item => countMap[item.json.NOME] > 1);

// Ordenar os duplicados pelo campo 'NOME'
duplicates.sort((a, b) => {
    if (a.json.NOME < b.json.NOME) return -1;
    if (a.json.NOME > b.json.NOME) return 1;
    return 0;
});

// Retornar os itens duplicados ordenados
return duplicates;

